                setApiKey={setApiKey}
                removeAuth={removeAuth}
                registerCustomProvider={registerCustomProvider}
                testProvider={testProvider}
                getProviderConfig={getProviderConfig}
                onAuthChange={() => { getAvailableModels() }}
              />
            )}
          </div>

          {isSessionTabActive && (
            <InputBar
              onSend={handleSendPrompt}
              disabled={!isConnected}
              isConnected={isConnected}
              isStreaming={displayedStreaming}
              onStop={handleStop}
              isLazySwitched={isLazySwitched}
              backgroundSessionName={backgroundSessionName}
              isBackgroundStreaming={isLazySwitched && isPiStreaming()}
              isAgentEnding={isAgentEnding}
              currentModel={currentModel}
              onSetModel={setModel}
              getAvailableModels={getAvailableModels}
              files={indexedFiles}
              sentMessages={sentMessages}
            />
          )}
        </div>

        <RightPanel
          view={rightPanelView}
          onViewChange={setRightPanelView}
          collapsed={rightPanelCollapsed}
          onToggleCollapse={() => toggleRightPanel()}
          width={rightPanelWidth}
          onResizeStart={handleRightResizeStart}
          onFileSelect={handleFileSelect}
          onDiffSelect={handleDiffSelect}
        />
      </div>

       {showWelcome && (
          <WelcomeDialog
            getProviderAuthStatus={getProviderAuthStatus}
            setApiKey={setApiKey}
            removeAuth={removeAuth}
            registerCustomProvider={registerCustomProvider}
             testProvider={testProvider}
             getProviderConfig={getProviderConfig}
             onAuthChange={() => {
              getAvailableModels()
            }}
            onSkip={() => setShowWelcome(false)}
          />
       )}

      <CommandPalette
        open={paletteOpen}
        onOpenChange={setPaletteOpen}
        files={indexedFiles}
        filesLoading={filesLoading}
        sessions={(sessions?.projects?.flatMap(p => p.allSessions) ?? []).map(s => ({
          name: s.name || '',
          filePath: s.filePath,
          isCurrent: s.filePath === currentSession?.filePath,
        }))}
        commands={commands}
        onFileSelect={(filePath) => addTab({ type: 'file', title: filePath.split(/[/\\]/).pop() ?? filePath, closable: true, meta: { filePath } })}
        onSessionSelect={(sessionPath) => switchSession(sessionPath)}
      />
    </div>
  )
}

export default App

import { useState, useCallback, useEffect } from 'react'
import type { SessionListResult, SessionInfo, SessionTreeNode } from '../types/session'
import TreeGraphRow, { sessionAncestorLinesToGuides, sessionDotToGuide } from './TreeGraph'

interface SessionSidebarProps {
  sessions: SessionListResult | null
  currentSession: SessionInfo | null
  onSwitchSession: (sessionPath: string) => void
  onNewSession: (name: string, parentSessionPath: string) => void
  onRenameSession: (name: string) => void
  onDeleteSession: (sessionPath: string) => Promise<boolean>
  onSetSessionStatus: (sessionPath: string, status: 'active' | 'completed') => Promise<boolean>
  onForkFromEnd: (sessionPath: string, name: string) => void
  isCollapsed: boolean
  onToggleCollapse: () => void
  width: number
  onResizeStart: (e: React.MouseEvent) => void
}

function formatRelativeTime(isoTimestamp: string): string {
  const now = Date.now()
  const then = new Date(isoTimestamp).getTime()
  const diffMs = now - then
  const diffMin = Math.floor(diffMs / 60000)
  const diffHr = Math.floor(diffMs / 3600000)
  const diffDay = Math.floor(diffMs / 86400000)

  if (diffMin < 1) return 'just now'
  if (diffMin < 60) return `${diffMin}m ago`
  if (diffHr < 24) return `${diffHr}h ago`
  if (diffDay < 30) return `${diffDay}d ago`
  return new Date(isoTimestamp).toLocaleDateString()
}

function getDisplayName(session: SessionInfo): string {
  if (session.name) return session.name
  const d = new Date(session.createdAt)
  const month = d.toLocaleString('en', { month: 'short' })
  const day = d.getDate()
  const hh = String(d.getHours()).padStart(2, '0')
  const mm = String(d.getMinutes()).padStart(2, '0')
  return `${month} ${day} ${hh}:${mm}`
}

const GRAY = '#e5e7eb'
const BLUE = '#3b82f6'

function isDescendantOf(node: SessionTreeNode, sessionPath: string | null): boolean {
  if (!sessionPath) return false
  if (node.session.filePath === sessionPath) return true
  return node.children.some((child) => isDescendantOf(child, sessionPath))
}



function SessionNode({
  node,
  ancestorLines,
  currentSessionPath,
  isOnActivePath,
  onSwitch,
  onRename,
  onDelete,
  onSetSessionStatus,
  onForkFromEnd,
  onNewSession,
  onContextMenu,
  triggerRenamePath,
  onRenameTriggered,
  triggerForkPath,
  onForkTriggered,
}: {
  node: SessionTreeNode
  ancestorLines: { hasLine: boolean; highlight: boolean; branchActive: boolean }[]
  currentSessionPath: string | null
  isOnActivePath: boolean
  onSwitch: (path: string) => void
  onRename: (name: string) => void
  onDelete: (path: string) => Promise<boolean>
  onSetSessionStatus: (sessionPath: string, status: 'active' | 'completed') => Promise<boolean>
  onForkFromEnd: (sessionPath: string, name: string) => void
  onNewSession: (name: string, parentSessionPath: string) => void
  onContextMenu: (e: React.MouseEvent, session: SessionInfo) => void
  triggerRenamePath: string | null
  onRenameTriggered: () => void
  triggerForkPath: string | null
  onForkTriggered: () => void
}): React.ReactElement {
  const [isExpanded, setIsExpanded] = useState(true)
  const [isRenaming, setIsRenaming] = useState(false)
  const [renameValue, setRenameValue] = useState(getDisplayName(node.session))
  const [confirmDelete, setConfirmDelete] = useState(false)
  const [isForking, setIsForking] = useState(false)
  const [forkName, setForkName] = useState('')
  const [isCreatingChild, setIsCreatingChild] = useState(false)
  const [childName, setChildName] = useState('')
  const isCompleted = node.session.status === 'completed'
  const isActive = currentSessionPath === node.session.filePath
  const hasChildren = node.children.length > 0

  useEffect(() => {
    if (triggerRenamePath === node.session.filePath) {
      setIsRenaming(true)
      setRenameValue(getDisplayName(node.session))
      onRenameTriggered()
    }
  }, [triggerRenamePath, node.session.filePath, onRenameTriggered])

  useEffect(() => {
    if (triggerForkPath === node.session.filePath) {
      setIsForking(true)
      setForkName('')
      onForkTriggered()
    }
  }, [triggerForkPath, node.session.filePath, onForkTriggered])

  const handleDoubleClick = useCallback(() => {
    setIsRenaming(true)
    setRenameValue(getDisplayName(node.session))
  }, [node.session])

  const handleRenameSubmit = useCallback(() => {
    const trimmed = renameValue.trim()
    if (trimmed && trimmed !== getDisplayName(node.session)) {
      onRename(trimmed)
    }
    setIsRenaming(false)
  }, [renameValue, node.session, onRename])

  const hasChildOnActivePath = node.children.some(
    (child) =>
      currentSessionPath === child.session.filePath ||
      isDescendantOf(child, currentSessionPath)
  )

  const guides = [...sessionAncestorLinesToGuides(ancestorLines), sessionDotToGuide({
    active: isOnActivePath || isActive || node.session.isMain,
    hasChildren,
    isExpanded,
    highlight: hasChildOnActivePath,
    completed: isCompleted,
  })]

  return (
    <div>
      <div
        className={`group flex items-center rounded cursor-pointer transition-colors ${
          isActive
            ? isCompleted
              ? 'bg-gray-100 text-gray-400'
              : 'bg-gray-100 text-gray-900'
            : isCompleted
              ? 'text-gray-400 hover:bg-gray-100/60 hover:text-gray-500'
              : 'text-gray-600 hover:bg-gray-100/60 hover:text-gray-800'
        }`}
        onClick={() => onSwitch(node.session.filePath)}
        onDoubleClick={handleDoubleClick}
        onContextMenu={(e) => onContextMenu(e, node.session)}
      >
        <TreeGraphRow guides={guides}>
          <div className="flex-1 flex items-center gap-1 py-1.5 pr-2 min-w-0">
          {isRenaming ? (
            <input
              autoFocus
              value={renameValue}
              onChange={(e) => setRenameValue(e.target.value)}
              onBlur={handleRenameSubmit}
              onKeyDown={(e) => {
                if (e.key === 'Enter') handleRenameSubmit()
                if (e.key === 'Escape') setIsRenaming(false)
              }}
              onClick={(e) => e.stopPropagation()}
              className="flex-1 min-w-0 bg-gray-100 rounded px-1 py-0.5 text-xs text-gray-900 outline-none border border-gray-300 focus:border-blue-500"
            />
          ) : (
            <span className={`flex-1 truncate text-xs ${isCompleted ? 'line-through' : ''}`}>
              {getDisplayName(node.session)}
            </span>
          )}

          <span className="flex-shrink-0 text-[10px] text-gray-400 opacity-0 group-hover:opacity-100 transition-opacity">
            {formatRelativeTime(node.session.createdAt)}
          </span>

          {hasChildren && (
            <button
              onClick={(e) => {
                e.stopPropagation()
                setIsExpanded(!isExpanded)
              }}
              className="flex-shrink-0 rounded px-0.5 py-0.5 text-gray-400 hover:text-gray-600 hover:bg-gray-100 opacity-0 group-hover:opacity-100 transition-colors"
              title={isExpanded ? 'Collapse' : 'Expand'}
            >
              <svg
                className={`w-3 h-3 transition-transform ${isExpanded ? 'rotate-90' : ''}`}
                fill="currentColor"
                viewBox="0 0 20 20"
              >
                <path
                  fillRule="evenodd"
                  d="M7.21 14.77a.75.75 0 01.02-1.06L11.168 10 7.23 6.29a.75.75 0 111.04-1.08l4.5 4.25a.75.75 0 010 1.08l-4.5 4.25a.75.75 0 01-1.06-.02z"
                  clipRule="evenodd"
                />
              </svg>
            </button>
          )}

          {node.session.parentSessionPath && (
            <button
              onClick={(e) => {
                e.stopPropagation()
                onSwitch(node.session.parentSessionPath!)
              }}
              className="flex-shrink-0 rounded px-0.5 py-0.5 text-gray-400 hover:text-blue-500 hover:bg-gray-100 opacity-0 group-hover:opacity-100 transition-colors"
              title="Go to parent session"
            >
              <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                <path strokeLinecap="round" strokeLinejoin="round" d="M5 15l7-7 7 7" />
              </svg>
            </button>
          )}

          {isActive && (
            <button
              onClick={(e) => {
                e.stopPropagation()
                setIsForking(true)
                setForkName('')
              }}
              className="flex-shrink-0 rounded px-0.5 py-0.5 text-gray-400 hover:text-purple-500 hover:bg-gray-100 opacity-0 group-hover:opacity-100 transition-colors"
              title="Fork"
            >
              <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                <path strokeLinecap="round" strokeLinejoin="round" d="M5 12h4m6 0h4M12 5v4m0 6v4" />
                <circle cx="5" cy="12" r="2" />
                <circle cx="19" cy="12" r="2" />
                <circle cx="12" cy="5" r="2" />
                <circle cx="12" cy="19" r="2" />
              </svg>
            </button>
          )}

          <button
            onClick={(e) => {
              e.stopPropagation()
              setIsCreatingChild(true)
              setChildName('')
            }}
            className="flex-shrink-0 rounded px-0.5 py-0.5 text-gray-400 hover:text-blue-500 hover:bg-gray-100 opacity-0 group-hover:opacity-100 transition-colors"
            title="New child session"
          >
            <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
              <path strokeLinecap="round" strokeLinejoin="round" d="M12 4v16m8-8H4" />
            </svg>
          </button>

          {!node.session.isMain && (
            <button
              onClick={(e) => {
                e.stopPropagation()
                if (confirmDelete) {
                  onDelete(node.session.filePath)
                  setConfirmDelete(false)
                } else {
                  setConfirmDelete(true)
                }
              }}
              onBlur={() => setConfirmDelete(false)}
              className={`flex-shrink-0 rounded p-0.5 opacity-0 group-hover:opacity-100 transition-colors ${
                confirmDelete
                  ? 'bg-red-600 text-white opacity-100'
                  : 'text-gray-400 hover:text-red-500 hover:bg-gray-100'
              }`}
            >
              {confirmDelete ? (
                <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                  <path strokeLinecap="round" strokeLinejoin="round" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                </svg>
              ) : (
                <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                  <path strokeLinecap="round" strokeLinejoin="round" d="M6 18L18 6M6 6l12 12" />
                </svg>
              )}
            </button>
          )}
          </div>
        </TreeGraphRow>
      </div>

      {isForking && (
        <div
          className="flex items-center gap-1 pl-8 pr-2 py-1"
          onClick={(e) => e.stopPropagation()}
        >
          <input
            autoFocus
            value={forkName}
            onChange={(e) => setForkName(e.target.value)}
            onKeyDown={(e) => {
              if (e.key === 'Enter') {
                const trimmed = forkName.trim()
                if (trimmed) {
                  onForkFromEnd(node.session.filePath, trimmed)
                  setIsForking(false)
                  setForkName('')
                }
              }
              if (e.key === 'Escape') {
                setIsForking(false)
                setForkName('')
              }
            }}
            placeholder="Fork name"
            className="flex-1 min-w-0 rounded border border-purple-300 bg-white px-2 py-0.5 text-xs text-gray-900 outline-none focus:border-purple-500"
          />
          <button
            onClick={() => {
              const trimmed = forkName.trim()
              if (trimmed) {
                onForkFromEnd(node.session.filePath, trimmed)
                setIsForking(false)
                setForkName('')
              }
            }}
            disabled={!forkName.trim()}
            className="rounded bg-purple-600 px-2 py-0.5 text-xs font-medium text-white hover:bg-purple-500 disabled:opacity-40 disabled:cursor-not-allowed"
          >
            Fork
          </button>
          <button
            onClick={() => {
              setIsForking(false)
              setForkName('')
            }}
            className="rounded px-1 py-0.5 text-gray-400 hover:text-gray-600 hover:bg-gray-100 text-xs transition-colors"
            title="Cancel"
          >
            ✕
          </button>
        </div>
      )}

      {isCreatingChild && (
        <div
          className="flex items-center gap-1 pl-8 pr-2 py-1"
          onClick={(e) => e.stopPropagation()}
        >
          <input
            autoFocus
            value={childName}
            onChange={(e) => setChildName(e.target.value)}
            onKeyDown={(e) => {
              if (e.key === 'Enter') {
                const trimmed = childName.trim()
                if (trimmed) {
                  onNewSession(trimmed, node.session.filePath)
                  setIsCreatingChild(false)
                  setChildName('')
                }
              }
              if (e.key === 'Escape') {
                setIsCreatingChild(false)
                setChildName('')
              }
            }}
            placeholder="Child session name"
            className="flex-1 min-w-0 rounded border border-blue-300 bg-white px-2 py-0.5 text-xs text-gray-900 outline-none focus:border-blue-500"
          />
          <button
            onClick={() => {
              const trimmed = childName.trim()
              if (trimmed) {
                onNewSession(trimmed, node.session.filePath)
                setIsCreatingChild(false)
                setChildName('')
              }
            }}
            disabled={!childName.trim()}
            className="rounded bg-blue-600 px-2 py-0.5 text-xs font-medium text-white hover:bg-blue-500 disabled:opacity-40 disabled:cursor-not-allowed"
          >
            Create
          </button>
          <button
            onClick={() => {
              setIsCreatingChild(false)
              setChildName('')
            }}
            className="rounded px-1 py-0.5 text-gray-400 hover:text-gray-600 hover:bg-gray-100 text-xs transition-colors"
            title="Cancel"
          >
            ✕
          </button>
        </div>
      )}

      {hasChildren && isExpanded && (
        <div>
          {node.children.map((child, i) => {
            const childIsActivePath =
              currentSessionPath === child.session.filePath ||
              isDescendantOf(child, currentSessionPath)
            const laterSiblingOnActivePath = node.children
              .slice(i + 1)
              .some(
                (sibling) =>
                  currentSessionPath === sibling.session.filePath ||
                  isDescendantOf(sibling, currentSessionPath)
              )
            const onPath = childIsActivePath || laterSiblingOnActivePath
            const newAncestorLines = [
              ...ancestorLines.map((entry) => ({
                hasLine: entry.hasLine,
                highlight: entry.branchActive
                  ? (entry.highlight && childIsActivePath)
                  : entry.highlight,
                branchActive: entry.branchActive && childIsActivePath,
              })),
              {
                hasLine: i < node.children.length - 1,
                highlight: onPath,
                branchActive: childIsActivePath,
              },
            ]
            return (
              <SessionNode
                key={child.session.filePath}
                node={child}
                ancestorLines={newAncestorLines}
                currentSessionPath={currentSessionPath}
                isOnActivePath={childIsActivePath}
                onSwitch={onSwitch}
                onRename={onRename}
                onDelete={onDelete}
                onSetSessionStatus={onSetSessionStatus}
                onForkFromEnd={onForkFromEnd}
                onNewSession={onNewSession}
                onContextMenu={onContextMenu}
                triggerRenamePath={triggerRenamePath}
                onRenameTriggered={onRenameTriggered}
                triggerForkPath={triggerForkPath}
                onForkTriggered={onForkTriggered}
              />
            )
          })}
        </div>
      )}
    </div>
  )
}

function SessionSidebar({
  sessions,
  currentSession,
  onSwitchSession,
  onNewSession,
  onRenameSession,
  onDeleteSession,
  onSetSessionStatus,
  onForkFromEnd,
  isCollapsed,
  onToggleCollapse,
  width,
  onResizeStart,
}: SessionSidebarProps): React.ReactElement {
  const [contextMenu, setContextMenu] = useState<{
    x: number
    y: number
    session: SessionInfo
  } | null>(null)
  const [contextMenuPos, setContextMenuPos] = useState<{ x: number; y: number } | null>(null)
  const [triggerRenamePath, setTriggerRenamePath] = useState<string | null>(null)
  const [triggerForkPath, setTriggerForkPath] = useState<string | null>(null)

  const projects = sessions?.projects ?? []
  const root = projects[0]?.root ?? null

  const handleContextMenu = useCallback((e: React.MouseEvent, session: SessionInfo) => {
    e.preventDefault()
    e.stopPropagation()
    setContextMenu({ x: e.clientX, y: e.clientY, session })
    setContextMenuPos(null) // will be adjusted in useEffect
  }, [])

  const handleRenameTriggered = useCallback(() => {
    setTriggerRenamePath(null)
  }, [])

  const handleForkTriggered = useCallback(() => {
    setTriggerForkPath(null)
  }, [])

  useEffect(() => {
    if (!contextMenu) return

    const handleClick = () => setContextMenu(null)
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === 'Escape') setContextMenu(null)
    }

    document.addEventListener('click', handleClick)
    document.addEventListener('keydown', handleKeyDown)

    return () => {
      document.removeEventListener('click', handleClick)
      document.removeEventListener('keydown', handleKeyDown)
    }
  }, [contextMenu])

  // Adjust context menu position to keep it within viewport
  useEffect(() => {
    if (!contextMenu) return
    const el = document.querySelector('[data-context-menu]') as HTMLDivElement | null
    if (!el) return
    const rect = el.getBoundingClientRect()
    const vw = window.innerWidth
    const vh = window.innerHeight
    let x = contextMenu.x
    let y = contextMenu.y
    if (x + rect.width > vw) x = vw - rect.width - 4
    if (y + rect.height > vh) y = vh - rect.height - 4
    if (x < 0) x = 4
    if (y < 0) y = 4
    setContextMenuPos({ x, y })
  }, [contextMenu])

  if (isCollapsed) {
    return (
      <div className="flex flex-col items-center w-12 bg-gray-50 border-r border-gray-200 pb-3" />
    )
  }

  return (
    <div
      className="relative flex flex-col bg-gray-50 overflow-hidden"
      style={{ width: `${width}px` }}
    >
      <div className="flex-1 overflow-y-auto py-2">
        {projects.length === 0 || !root ? (
          <div className="px-3 py-6 text-center text-xs text-gray-600">
            No sessions found
          </div>
        ) : (
          <SessionNode
            node={root}
            ancestorLines={[]}
            currentSessionPath={currentSession?.filePath ?? null}
            isOnActivePath={true}
            onSwitch={onSwitchSession}
            onRename={onRenameSession}
            onDelete={onDeleteSession}
            onSetSessionStatus={onSetSessionStatus}
            onForkFromEnd={onForkFromEnd}
            onNewSession={onNewSession}
            onContextMenu={handleContextMenu}
            triggerRenamePath={triggerRenamePath}
            onRenameTriggered={handleRenameTriggered}
            triggerForkPath={triggerForkPath}
            onForkTriggered={handleForkTriggered}
          />
        )}
      </div>

      <div
        className="absolute top-0 right-0 w-1 h-full cursor-col-resize hover:w-1.5 hover:bg-blue-500/30 transition-all z-10"
        onMouseDown={onResizeStart}
      />

      {contextMenu && (
        <div
          data-context-menu
          className="fixed z-50 bg-white border border-gray-200 rounded-lg shadow-lg py-1 text-xs min-w-[140px]"
          style={{ left: contextMenuPos?.x ?? contextMenu.x, top: contextMenuPos?.y ?? contextMenu.y }}
          onClick={(e) => e.stopPropagation()}
        >
          <div
            className="px-3 py-1.5 hover:bg-gray-100 cursor-pointer"
            onClick={() => {
              setTriggerRenamePath(contextMenu.session.filePath)
              setContextMenu(null)
            }}
          >
            Rename
          </div>
          <div
            className="px-3 py-1.5 hover:bg-gray-100 cursor-pointer"
            onClick={() => {
              const newStatus = contextMenu.session.status === 'completed' ? 'active' : 'completed'
              onSetSessionStatus(contextMenu.session.filePath, newStatus)
              setContextMenu(null)
            }}
          >
            {contextMenu.session.status === 'completed' ? 'Mark as active' : 'Mark as completed'}
          </div>
          {contextMenu.session.parentSessionPath && (
            <div
              className="px-3 py-1.5 hover:bg-gray-100 cursor-pointer"
              onClick={() => {
                onSwitchSession(contextMenu.session.parentSessionPath!)
                setContextMenu(null)
              }}
            >
              Go to parent
            </div>
          )}
          {contextMenu.session.filePath === currentSession?.filePath && (
            <div
              className="px-3 py-1.5 hover:bg-purple-50 cursor-pointer text-purple-600"
              onClick={() => {
                setTriggerForkPath(contextMenu.session.filePath)
                setContextMenu(null)
              }}
            >
              Fork
            </div>
          )}
          {!contextMenu.session.isMain && (
            <div
              className="px-3 py-1.5 hover:bg-red-50 cursor-pointer text-red-600"
              onClick={() => {
                onDeleteSession(contextMenu.session.filePath)
                setContextMenu(null)
              }}
            >
              Delete
            </div>
          )}
        </div>
      )}
    </div>
  )
}

export default SessionSidebar

/**
 * useSessionCache — Manages per-session message caching for Lazy Session Switch.
 *
 * Decouples the "displayed session" (what the user sees) from the
 * "Pi-connected session" (which session the Pi worker is on).
 * When they differ, the displayed session is in read-only mode.
 *
 * Pi events are always written to the Pi-connected session's cache.
 * The UI is only refreshed when the displayed session matches the
 * Pi-connected session (or when the user explicitly switches).
 */
import { useState, useCallback, useRef } from 'react'
import type { ChatMessage, ContentBlock } from '../types/message'
import type { ForkPoint } from '../types/session'
import { convertPiMessagesToChatMessages, type TokenUsage } from '../utils/convert-messages'

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

export interface SessionCache {
  sessionPath: string
  messages: ChatMessage[]
  isStreaming: boolean
  streamingMessageId: string | null
  tokenUsage: TokenUsage
  forkPoints: ForkPoint[]
  loadedAt: number

  // Pi streaming intermediate state — needed to resume receiving deltas
  // after switching away and back to a streaming session
  currentAssistantId: string | null
  currentContentBlocks: Map<number, ContentBlock>
  toolCallArgsBuffer: Map<number, string>
  pendingToolCallArgs: Map<string, Record<string, unknown>>
  countedResponseIds: Set<string>
}

interface UseSessionCacheReturn {
  // What the user is looking at
  displayedSessionPath: string | null
  // Messages for the displayed session
  displayedMessages: ChatMessage[]
  // Whether the displayed session is streaming
  isDisplayedStreaming: boolean
  // Token usage for the displayed session
  displayedTokenUsage: TokenUsage
  // Fork points for the displayed session
  displayedForkPoints: ForkPoint[]
  // Streaming message ID for the displayed session
  displayedStreamingMessageId: string | null

  // Get cache for a specific session
  getCache: (sessionPath: string) => SessionCache | undefined
  // Get or create cache for a session (loads from JSONL if not cached)
  getOrCreateCache: (sessionPath: string) => Promise<SessionCache>
  // Update a session's cache (used by usePiRpc to write streaming events)
  updateCache: (sessionPath: string, updater: (cache: SessionCache) => SessionCache) => void
  // Switch the displayed session (does NOT switch Pi connection)
  displaySession: (sessionPath: string) => Promise<void>
  // Clear a session's cache
  clearCache: (sessionPath: string) => void
  // Mark a session as streaming / not streaming
  setCacheStreaming: (sessionPath: string, isStreaming: boolean, streamingMessageId: string | null) => void
  // Refresh displayed messages from cache (after cache updates)
  refreshDisplayedMessages: () => void

  updatePiConnectedMessages: (piConnectedPath: string, updater: (prev: ChatMessage[]) => ChatMessage[]) => void
  updatePiConnectedTokenUsage: (piConnectedPath: string, updater: (prev: TokenUsage) => TokenUsage) => void
  setPiConnectedStreaming: (piConnectedPath: string, isStreaming: boolean, streamingMessageId: string | null) => void
  updatePiConnectedForkPoints: (piConnectedPath: string, forkPoints: ForkPoint[]) => void
}

// ---------------------------------------------------------------------------
// Initial values
// ---------------------------------------------------------------------------

const INITIAL_TOKEN_USAGE: TokenUsage = {
  inputTokens: 0,
  outputTokens: 0,
  cacheReadTokens: 0,
  cacheWriteTokens: 0,
  totalTokens: 0,
  totalCost: 0,
  contextWindowSize: 200000,
}

function createEmptyCache(sessionPath: string): SessionCache {
  return {
    sessionPath,
    messages: [],
    isStreaming: false,
    streamingMessageId: null,
    tokenUsage: { ...INITIAL_TOKEN_USAGE },
    forkPoints: [],
    loadedAt: 0,
    currentAssistantId: null,
    currentContentBlocks: new Map(),
    toolCallArgsBuffer: new Map(),
    pendingToolCallArgs: new Map(),
    countedResponseIds: new Set(),
  }
}

// ---------------------------------------------------------------------------
// Hook
// ---------------------------------------------------------------------------

export function useSessionCache(): UseSessionCacheReturn {
  const cacheMap = useRef<Map<string, SessionCache>>(new Map())

  const [displayedSessionPath, setDisplayedSessionPath] = useState<string | null>(null)
  const [displayedMessages, setDisplayedMessages] = useState<ChatMessage[]>([])
  const [displayedTokenUsage, setDisplayedTokenUsage] = useState<TokenUsage>({ ...INITIAL_TOKEN_USAGE })
  const [displayedForkPoints, setDisplayedForkPoints] = useState<ForkPoint[]>([])
  const [isDisplayedStreaming, setIsDisplayedStreaming] = useState(false)
  const [displayedStreamingMessageId, setDisplayedStreamingMessageId] = useState<string | null>(null)

  // Use a ref for displayedSessionPath to avoid circular dep chains
  // (callbacks that read displayedSessionPath also set it via setDisplayedSessionPath)
  const displayedSessionPathRef = useRef<string | null>(null)

  const syncDisplayedFromCache = useCallback((sessionPath: string | null) => {
    if (!sessionPath) {
      setDisplayedMessages([])
      setDisplayedTokenUsage({ ...INITIAL_TOKEN_USAGE })
      setDisplayedForkPoints([])
      setIsDisplayedStreaming(false)
      setDisplayedStreamingMessageId(null)
      return
    }
    const cache = cacheMap.current.get(sessionPath)
    if (cache) {
      setDisplayedMessages(cache.messages)
      setDisplayedTokenUsage(cache.tokenUsage)
      setDisplayedForkPoints(cache.forkPoints)
      setIsDisplayedStreaming(cache.isStreaming)
      setDisplayedStreamingMessageId(cache.streamingMessageId)
    }
  }, [])

  const getCache = useCallback((sessionPath: string): SessionCache | undefined => {
    return cacheMap.current.get(sessionPath)
  }, [])

  const getOrCreateCache = useCallback(async (sessionPath: string): Promise<SessionCache> => {
    const existing = cacheMap.current.get(sessionPath)
    if (existing) return existing

    // Load from JSONL via IPC
    let cache: SessionCache = createEmptyCache(sessionPath)
    try {
      type ApiWithGetMessagesForSession = typeof window.api & {
        getMessagesForSession: (path: string) => Promise<unknown[]>
      }
      const api = window.api as ApiWithGetMessagesForSession
      const piMessages = await api.getMessagesForSession(sessionPath)

      if (Array.isArray(piMessages) && piMessages.length > 0) {
        const result = convertPiMessagesToChatMessages(piMessages)
        cache = {
          ...cache,
          messages: result.messages,
          tokenUsage: result.tokenUsage,
          loadedAt: Date.now(),
          countedResponseIds: new Set(result.responseIds),
        }
      }
    } catch {
      // JSONL read failed — show empty state
    }

    cacheMap.current.set(sessionPath, cache)
    return cache
  }, [])

  const updateCache = useCallback((sessionPath: string, updater: (cache: SessionCache) => SessionCache) => {
    const existing = cacheMap.current.get(sessionPath)
    if (!existing) return
    const updated = updater(existing)
    cacheMap.current.set(sessionPath, updated)

    // If this is the displayed session, sync UI
    if (sessionPath === displayedSessionPathRef.current) {
      setDisplayedMessages(updated.messages)
      setDisplayedTokenUsage(updated.tokenUsage)
      setDisplayedForkPoints(updated.forkPoints)
      setIsDisplayedStreaming(updated.isStreaming)
      setDisplayedStreamingMessageId(updated.streamingMessageId)
    }
  }, [])

  const displaySession = useCallback(async (sessionPath: string) => {
    displayedSessionPathRef.current = sessionPath
    setDisplayedSessionPath(sessionPath)
    const cache = await getOrCreateCache(sessionPath)
    if (displayedSessionPathRef.current !== sessionPath) return
    syncDisplayedFromCache(sessionPath)

    try {
      type ApiWithForkPoints = typeof window.api & {
        getForkPoints: (path: string) => Promise<ForkPoint[]>
      }
      const api = window.api as ApiWithForkPoints
      const points = await api.getForkPoints(sessionPath)
      if (displayedSessionPathRef.current !== sessionPath) return
      const updated: SessionCache = { ...cache, forkPoints: points }
      cacheMap.current.set(sessionPath, updated)
      if (sessionPath === displayedSessionPathRef.current) {
        setDisplayedForkPoints(points)
      }
    } catch {
      // ignore
    }
  }, [getOrCreateCache, syncDisplayedFromCache])

  const clearCache = useCallback((sessionPath: string) => {
    cacheMap.current.delete(sessionPath)
    if (sessionPath === displayedSessionPathRef.current) {
      syncDisplayedFromCache(displayedSessionPathRef.current)
    }
  }, [syncDisplayedFromCache])

  const setCacheStreaming = useCallback((sessionPath: string, isStreaming: boolean, streamingMessageId: string | null) => {
    const cache = cacheMap.current.get(sessionPath)
    if (!cache) return
    const updated = { ...cache, isStreaming, streamingMessageId }
    cacheMap.current.set(sessionPath, updated)
    if (sessionPath === displayedSessionPathRef.current) {
      setIsDisplayedStreaming(isStreaming)
      setDisplayedStreamingMessageId(streamingMessageId)
    }
  }, [])

  const refreshDisplayedMessages = useCallback(() => {
    syncDisplayedFromCache(displayedSessionPathRef.current)
  }, [syncDisplayedFromCache])

  const updatePiConnectedMessages = useCallback((piConnectedPath: string, updater: (prev: ChatMessage[]) => ChatMessage[]) => {
    const cache = cacheMap.current.get(piConnectedPath)
    if (!cache) return
    const updatedMessages = updater(cache.messages)
    const updated = { ...cache, messages: updatedMessages }
    cacheMap.current.set(piConnectedPath, updated)

    if (piConnectedPath === displayedSessionPathRef.current) {
      setDisplayedMessages(updatedMessages)
    }
  }, [])

  const updatePiConnectedTokenUsage = useCallback((piConnectedPath: string, updater: (prev: TokenUsage) => TokenUsage) => {
    const cache = cacheMap.current.get(piConnectedPath)
    if (!cache) return
    const updatedTokenUsage = updater(cache.tokenUsage)
    const updated = { ...cache, tokenUsage: updatedTokenUsage }
    cacheMap.current.set(piConnectedPath, updated)

    if (piConnectedPath === displayedSessionPathRef.current) {
      setDisplayedTokenUsage(updatedTokenUsage)
    }
  }, [])

  const setPiConnectedStreaming = useCallback((piConnectedPath: string, isStreaming: boolean, streamingMessageId: string | null) => {
    const cache = cacheMap.current.get(piConnectedPath)
    if (!cache) return
    const updated = { ...cache, isStreaming, streamingMessageId }
    cacheMap.current.set(piConnectedPath, updated)

    if (piConnectedPath === displayedSessionPathRef.current) {
      setIsDisplayedStreaming(isStreaming)
      setDisplayedStreamingMessageId(streamingMessageId)
    }
  }, [])

  const updatePiConnectedForkPoints = useCallback((piConnectedPath: string, forkPoints: ForkPoint[]) => {
    const cache = cacheMap.current.get(piConnectedPath)
    if (!cache) return
    const updated = { ...cache, forkPoints }
    cacheMap.current.set(piConnectedPath, updated)

    if (piConnectedPath === displayedSessionPathRef.current) {
      setDisplayedForkPoints(forkPoints)
    }
  }, [])

  return {
    displayedSessionPath,
    displayedMessages,
    isDisplayedStreaming,
    displayedTokenUsage,
    displayedForkPoints,
    displayedStreamingMessageId,
    getCache,
    getOrCreateCache,
    updateCache,
    displaySession,
    clearCache,
    setCacheStreaming,
    refreshDisplayedMessages,
    updatePiConnectedMessages,
    updatePiConnectedTokenUsage,
    setPiConnectedStreaming,
    updatePiConnectedForkPoints,
  }
}

/**
 * Session management types for Pi session sidebar.
 *
 * Pi sessions are stored as JSONL files at:
 *   ~/.pi/agent/sessions/--<encoded-cwd>--/<timestamp>_<uuid>.jsonl
 *
 * Each file has a tree structure (id/parentId) and a header with metadata.
 * Inter-session relationships are tracked via `parentSession` in the header.
 */

/** Parsed header from a Pi session JSONL file (first line). */
export interface SessionFileHeader {
  type: 'session'
  version: number
  id: string
  timestamp: string
  cwd: string
  parentSession?: string
}

/** Lightweight metadata for a session file, used in the sidebar list. */
export interface SessionInfo {
  /** Absolute path to the .jsonl file on disk. */
  filePath: string
  /** UUID from the session header. */
  sessionId: string
  /** User-defined display name (from session_info entries), or null. */
  name: string | null
  /** ISO timestamp of session creation. */
  createdAt: string
  /** Working directory the session was started in. */
  cwd: string
  /** Absolute path to the parent session file, or null. */
  parentSessionPath: string | null
  /** Number of user messages in the session. */
  messageCount: number
  /** Whether this is the "main" session for its project. */
  isMain: boolean
  /** Session status: 'active' or 'completed'. null means active (default). */
  status: 'active' | 'completed' | null
}

/**
 * A node in the inter-session tree.
 * Each project has a tree of sessions linked by parentSession.
 */
export interface SessionTreeNode {
  session: SessionInfo
  children: SessionTreeNode[]
}

/**
 * A project's session tree.
 * Each project (working directory) has one tree rooted at the "main" session.
 */
export interface ProjectSessionTree {
  /** The decoded working directory path. */
  projectPath: string
  /** The encoded directory name (e.g., "--Users-foo-bar--"). */
  encodedDir: string
  /** Root of the session tree (the "main" session). */
  root: SessionTreeNode | null
  /** All sessions in this project (flat list for lookup). */
  allSessions: SessionInfo[]
}

/** Result of listing all sessions across all projects. */
export interface SessionListResult {
  projects: ProjectSessionTree[]
}

/** A forkable user message entry (from get_fork_messages RPC). */
export interface ForkableMessage {
  entryId: string
  text: string
}

/** A recorded fork point in a parent session's JSONL file. */
export interface ForkPoint {
  entryId: string
  childName: string
}

/** IPC channels for session management between renderer and main process. */
export interface SessionIpcApi {
  /** List all sessions grouped by project. */
  listSessions: () => Promise<SessionListResult>
  /** Get forkable user messages for the current session. */
  getForkMessages: () => Promise<ForkableMessage[]>
  /** Fork at a specific entry, creating a new session. */
  forkAtEntry: (entryId: string, name?: string) => Promise<{ success: boolean; text?: string; error?: string }>
  /** Switch to a different session. */
  switchSession: (sessionPath: string) => Promise<{ success: boolean; error?: string }>
  /** Create a new session with a name and optional parent. */
  newSession: (name: string, parentSessionPath?: string) => Promise<{ success: boolean; error?: string }>
  /** Rename a session. */
  renameSession: (name: string) => Promise<{ success: boolean; error?: string }>
  /** Get current session state. */
  getCurrentSession: () => Promise<SessionInfo | null>
  /** Refresh session list (after fork/switch/new operations). */
  refreshSessions: () => Promise<SessionListResult>
  /** Get all messages in the current Pi session (raw Pi message format). */
  getMessages: () => Promise<unknown[]>
  /** Delete a session by file path. Cannot delete the active session. */
  deleteSession: (sessionPath: string) => Promise<{ success: boolean; error?: string }>
  /** Get fork points recorded in a session file. */
  getForkPoints: (sessionPath: string) => Promise<ForkPoint[]>
  /** Clear the current session's conversation (delete JSONL, restart Pi, rename). */
  clearSession: () => Promise<{ success: boolean; error?: string }>
  /** Set session status (active/completed). Pure file operation, no Pi RPC. */
  setSessionStatus: (sessionPath: string, status: 'active' | 'completed') => Promise<{ success: boolean; error?: string }>
}

/** Model info returned by Pi SDK. */
export interface PiModelInfo {
  provider: string
  id: string
  name: string
  hasAuth: boolean
  reasoning: boolean
  contextWindow: number
}

/** Result from getAvailableModels IPC call. */
export interface GetAvailableModelsResult {
  ok: boolean
  data?: { models: PiModelInfo[] }
  error?: string
}

/** Result from setModel IPC call. */
export interface SetModelResult {
  ok: boolean
  data?: PiModelInfo | null
  error?: string
}

/** Result from cycleModel IPC call. */
export interface CycleModelResult {
  ok: boolean
  data?: {
    model: PiModelInfo | null
    thinkingLevel: string
    isScoped: boolean
  }
  error?: string
}

/** Result from getModelInfo IPC call. */
export interface GetModelInfoResult {
  ok: boolean
  data?: { model: PiModelInfo | null; thinkingLevel: string | null }
  error?: string
}

/** IPC channels for file system operations between renderer and main process. */
export interface FileSystemIpcApi {
  readDirectory: (dirPath: string) => Promise<{
    ok: boolean
    entries?: Array<{ name: string; path: string; isDirectory: boolean }>
    error?: string
  }>
}

import { app, BrowserWindow, ipcMain, nativeTheme, dialog, shell } from 'electron'
import { join, basename, extname, dirname } from 'path'
import { existsSync, readdirSync, statSync, readFileSync, writeFileSync, mkdirSync } from 'fs'
import { execFile } from 'child_process'
import { simpleGit } from 'simple-git'
import { watch } from 'chokidar'
import { PiSDKBridge } from './pi-sdk-bridge'
import * as sessionService from './session-service'
import type { SessionInfo, ForkableMessage, ForkPoint } from '../renderer/src/types/session'

// Override app name & dock icon so macOS shows "Xi" instead of "Electron"
app.setName('Xi')
if (process.platform === 'darwin') {
  try {
    const dockIconPath = join(__dirname, 'icon.png')
    app.dock.setIcon(dockIconPath)
  } catch {}
}

let mainWindow: BrowserWindow | null = null
let piBridge: PiSDKBridge | null = null
let initialSessionPath: string | undefined

function createWindow(): void {
  const iconPath = join(__dirname, 'icon.png')
  mainWindow = new BrowserWindow({
    width: 1200,
    height: 800,
    backgroundColor: '#ffffff',
    titleBarStyle: 'hiddenInset',
    icon: iconPath,
    show: false,
    webPreferences: {
      preload: join(__dirname, '../preload/index.js'),
      sandbox: false
    }
  })

  mainWindow.on('ready-to-show', () => {
    mainWindow?.show()
  })

  mainWindow.on('closed', () => {
    mainWindow = null
  })

  mainWindow.webContents.on('context-menu', (event) => {
    event.preventDefault()
  })

  if (process.env.ELECTRON_RENDERER_URL) {
    mainWindow.loadURL(process.env.ELECTRON_RENDERER_URL)
  } else {
    mainWindow.loadFile(join(__dirname, '../renderer/index.html'))
  }
}

function broadcastToRenderers(channel: string, data: unknown): void {
  BrowserWindow.getAllWindows().forEach((win) => {
    if (!win.isDestroyed() && !win.webContents.isDestroyed()) {
      try {
        win.webContents.send(channel, data)
      } catch {}
    }
  })
}

function initPiBridge(sessionPath?: string): void {
  piBridge = new PiSDKBridge()
  initialSessionPath = sessionPath

  piBridge.on('event', (data: unknown) => {
    // In SDK mode, extension_ui_request arrives as a regular event
    if (typeof data === 'object' && data !== null) {
      const obj = data as Record<string, unknown>
      if (obj.type === 'extension_ui_request') {
        broadcastToRenderers('pi:extensionUiRequest', data)
        return
      }
    }
    broadcastToRenderers('pi:event', data)
  })

  piBridge.on('response', (data: unknown) => {
    broadcastToRenderers('pi:response', data)
  })

  piBridge.on('connected', () => {
    broadcastToRenderers('pi:stateChanged', { connected: true })
  })

  piBridge.on('disconnected', () => {
    broadcastToRenderers('pi:stateChanged', { connected: false })
  })

  piBridge.on('error', (err: Error) => {
    console.error('[PiSDKBridge]', err.message)
  })
}

function registerIpcHandlers(): void {
  ipcMain.handle('pi:sendCommand', (_event, command: Record<string, unknown>) => {
    if (!piBridge?.isConnected) return { ok: false, error: 'Pi not connected' }
    piBridge.sendCommand(command)
    return { ok: true }
  })

  ipcMain.handle('pi:sendExtensionUIResponse', (_event, response: Record<string, unknown>) => {
    if (!piBridge?.isConnected) return { ok: false, error: 'Pi not connected' }
    piBridge.sendExtensionUIResponse(response)
    return { ok: true }
  })

  ipcMain.handle('pi:getState', () => {
    return { connected: piBridge?.isConnected ?? false }
  })

  ipcMain.handle('pi:getAvailableModels', async () => {
    if (!piBridge?.isConnected) return { ok: false, error: 'Pi not connected' }
    try {
      const data = await piBridge.sendRpcCommand({ type: 'get_available_models' })
      return { ok: true, data }
    } catch (err: unknown) {
      return { ok: false, error: err instanceof Error ? err.message : String(err) }
    }
  })

  ipcMain.handle('pi:setModel', async (_event, model: string, provider?: string) => {
    if (!piBridge?.isConnected) return { ok: false, error: 'Pi not connected' }
    try {
      const command: Record<string, unknown> = { type: 'set_model', model }
      if (provider) command.provider = provider
      const data = await piBridge.sendRpcCommand(command)
      return { ok: true, data }
    } catch (err: unknown) {
      return { ok: false, error: err instanceof Error ? err.message : String(err) }
    }
  })

  ipcMain.handle('pi:cycleModel', async (_event, direction?: 'forward' | 'backward') => {
    if (!piBridge?.isConnected) return { ok: false, error: 'Pi not connected' }
    try {
      const data = await piBridge.sendRpcCommand({ type: 'cycle_model', direction: direction ?? 'forward' })
      return { ok: true, data }
    } catch (err: unknown) {
      return { ok: false, error: err instanceof Error ? err.message : String(err) }
    }
  })

  ipcMain.handle('pi:getModelInfo', async () => {
    if (!piBridge?.isConnected) return { ok: false, error: 'Pi not connected' }
    try {
      const data = await piBridge.sendRpcCommand({ type: 'get_state' })
      const state = data as Record<string, unknown>
      return { ok: true, data: { model: state.model ?? null, thinkingLevel: state.thinkingLevel ?? null } }
    } catch (err: unknown) {
      return { ok: false, error: err instanceof Error ? err.message : String(err) }
    }
  })

  ipcMain.handle('pi:getProviderAuthStatus', async () => {
    if (!piBridge?.isConnected) return { ok: false, error: 'Pi not connected' }
    try {
      const data = await piBridge.sendRpcCommand({ type: 'get_provider_auth_status' })
      return { ok: true, data }
    } catch (err: unknown) {
      return { ok: false, error: err instanceof Error ? err.message : String(err) }
    }
  })

  ipcMain.handle('pi:setApiKey', async (_event, provider: string, apiKey: string) => {
    if (!piBridge?.isConnected) return { ok: false, error: 'Pi not connected' }
    try {
      await piBridge.sendRpcCommand({ type: 'set_api_key', provider, apiKey })
      return { ok: true }
    } catch (err: unknown) {
      return { ok: false, error: err instanceof Error ? err.message : String(err) }
    }
  })

  ipcMain.handle('pi:removeAuth', async (_event, provider: string) => {
    if (!piBridge?.isConnected) return { ok: false, error: 'Pi not connected' }
    try {
      await piBridge.sendRpcCommand({ type: 'remove_auth', provider })
      return { ok: true }
    } catch (err: unknown) {
      return { ok: false, error: err instanceof Error ? err.message : String(err) }
    }
  })

  ipcMain.handle('pi:registerCustomProvider', async (_event, provider: string, config: Record<string, unknown>) => {
    if (!piBridge?.isConnected) return { ok: false, error: 'Pi not connected' }
    try {
      await piBridge.sendRpcCommand({ type: 'register_custom_provider', provider, config })
      return { ok: true }
    } catch (err: unknown) {
      return { ok: false, error: err instanceof Error ? err.message : String(err) }
    }
  })

  ipcMain.handle('provider:getConfig', async (_event, provider: string) => {
    try {
      const homeDir = process.env.HOME ?? process.env.USERPROFILE ?? ''
      const configDir = join(homeDir, '.pi', 'agent')
      for (const configFile of ['models.json', 'settings.json']) {
        const configPath = join(configDir, configFile)
        if (existsSync(configPath)) {
          const data = JSON.parse(readFileSync(configPath, 'utf-8'))
          const providerData = data.providers?.[provider]
          if (providerData) return { ok: true, config: providerData }
        }
      }
      return { ok: false, error: 'Provider not found' }
    } catch (err: unknown) {
      return { ok: false, error: err instanceof Error ? err.message : String(err) }
    }
  })

  ipcMain.handle('provider:test', async (_event, provider: string, overrides?: { baseUrl?: string; apiKey?: string }) => {
    try {
      const providerBaseUrls: Record<string, string> = {
        anthropic: 'https://api.anthropic.com',
        openai: 'https://api.openai.com',
        google: 'https://generativelanguage.googleapis.com',
        deepseek: 'https://api.deepseek.com',
        openrouter: 'https://openrouter.ai',
        groq: 'https://api.groq.com',
        xai: 'https://api.x.ai',
        mistral: 'https://api.mistral.ai',
      }

      let baseUrl = overrides?.baseUrl ?? providerBaseUrls[provider]
      if (!baseUrl) {
        try {
          const homeDir = process.env.HOME ?? process.env.USERPROFILE ?? ''
          const configDir = join(homeDir, '.pi', 'agent')
          for (const configFile of ['models.json', 'settings.json']) {
            const configPath = join(configDir, configFile)
            if (existsSync(configPath)) {
              const data = JSON.parse(readFileSync(configPath, 'utf-8'))
              const custom = data.providers?.[provider]
              if (custom?.baseUrl) { baseUrl = custom.baseUrl; break }
            }
          }
        } catch {}
      }
      if (!baseUrl) return { ok: false, error: 'Unknown provider' }

      let apiKey = overrides?.apiKey ?? ''
      if (!apiKey) {
        const envMap: Record<string, string> = {
          anthropic: 'ANTHROPIC_API_KEY',
          openai: 'OPENAI_API_KEY',
          google: 'GOOGLE_API_KEY',
          deepseek: 'DEEPSEEK_API_KEY',
          openrouter: 'OPENROUTER_API_KEY',
          groq: 'GROQ_API_KEY',
          xai: 'XAI_API_KEY',
          mistral: 'MISTRAL_API_KEY',
        }
        const envKey = envMap[provider]
        if (envKey && process.env[envKey]) {
          apiKey = process.env[envKey]!
        }
      }
      if (!apiKey && piBridge?.isConnected) {
        try {
          const authData = await Promise.race([
            piBridge.sendRpcCommand({ type: 'get_provider_auth_status' }),
            new Promise<null>((resolve) => setTimeout(() => resolve(null), 3000)),
          ]) as Record<string, unknown> | null
          if (authData) {
            const authStatus = authData as Record<string, { configured: boolean; source?: string }>
            if (authStatus?.[provider]?.configured) {
              try {
                const keyData = await Promise.race([
                  piBridge.sendRpcCommand({ type: 'get_api_key', provider }),
                  new Promise<null>((resolve) => setTimeout(() => resolve(null), 3000)),
                ]) as Record<string, unknown> | null
                if (keyData && typeof keyData.apiKey === 'string') apiKey = keyData.apiKey
              } catch {}
            }
          }
        } catch {}
      }
      if (!apiKey) {
        try {
          const configDir = join(process.env.HOME ?? process.env.USERPROFILE ?? '~', '.pi', 'agent')
          for (const configFile of ['auth.json', 'models.json']) {
            const configPath = join(configDir, configFile)
            if (existsSync(configPath)) {
              const data = JSON.parse(readFileSync(configPath, 'utf-8'))
              const providerData = data[provider] ?? data.providers?.[provider]
              if (providerData?.apiKey) { apiKey = providerData.apiKey; break }
            }
          }
        } catch {}
      }
      if (!apiKey) return { ok: false, error: 'No API key configured' }

      const controller = new AbortController()
      const timeout = setTimeout(() => controller.abort(), 10_000)

      let url: string
      let headers: Record<string, string>
      if (provider === 'anthropic') {
        url = `${baseUrl}/v1/models`
        headers = { 'x-api-key': apiKey, 'anthropic-version': '2023-06-01' }
      } else if (provider === 'google') {
        url = `${baseUrl}/v1beta/models?key=${apiKey}`
        headers = {}
      } else {
        url = `${baseUrl}/v1/models`
        headers = { 'Authorization': `Bearer ${apiKey}` }
      }

      const start = Date.now()
      const response = await fetch(url, { signal: controller.signal, headers })
      clearTimeout(timeout)

      if (response.ok) {
        return { ok: true, latencyMs: Date.now() - start }
      }
      if (response.status === 401 || response.status === 403) {
        return { ok: false, error: 'Invalid API key' }
      }
      return { ok: false, error: `HTTP ${response.status}` }
    } catch (err: unknown) {
      if (err instanceof Error && err.name === 'AbortError') {
        return { ok: false, error: 'Connection timed out' }
      }
      if (err instanceof TypeError && err.cause instanceof Error) {
        const code = (err.cause as NodeJS.ErrnoException).code
        if (code === 'ECONNREFUSED' || code === 'ENOTFOUND') {
          return { ok: false, error: 'Cannot reach server' }
        }
      }
      return { ok: false, error: err instanceof Error ? err.message : String(err) }
    }
  })

